export function getCityListings(slug: string): Listing[] | null {
  const city = cities.find((c) => c.slug === slug);
  return city ? city.listings : null;
}

export function getCityName(slug: string): string | null {
  const city = cities.find((c) => c.slug === slug);
  return city ? city.name : null;
}
